示例：pc-sempc-sem.c <p>代码示例：信号量解决生产者-消费者问题</p> <p>在任意时刻，empty/fill 的数值就代表了当前还可以打印左括号/右括号的数量。而希望打印的线程，必须从相应的袋子里取走一个球。特别值得注意的是，我们总是把先把括号打印出来，再对相应的信号量执行 V 操作，这实现了生产者-消费者之间的同步。</p> <pre><code>#include "thread.h"
#include "thread-sync.h"
sem_t fill, empty;
void Tproduce() {
while (1) {
P(&amp;empty);
printf("(");
V(&amp;fill);
}
}
void Tconsume() {
while (1) {
P(&amp;fill);
printf(")");
V(&amp;empty);
}
}
int main(int argc, char *argv[]) {
assert(argc == 2);
SEM_INIT(&amp;fill, 0);
SEM_INIT(&amp;empty, atoi(argv[1]));
for (int i = 0; i &lt; 8; i++) {
create(Tproduce);
create(Tconsume);
}
}
</code></pre>

示例：join-semjoin-sem.c <p>代码示例：信号量实现线程 join</p> <p>一对 V-P 操作形成了 happens-before 关系，从而实现 “一件事等另一件事完成才能开始” 类型的同步。类似地，我们可以用信号量实现任意计算图的同步。相比于条件变量，由于 V 操作自带 count++，因此不用担心条件变量中唤醒丢失的情况。</p> <pre><code>#include "thread.h"
#include "thread-sync.h"
#define T 4
#define N 10000000
sem_t done;
long sum = 0;
void atomic_inc(long *ptr) {
asm volatile(
"lock incq %0"
: "+m"(*ptr) : : "memory"
);
}
void Tsum() {
for (int i = 0; i &lt; N; i++) {
atomic_inc(&amp;sum);
}
V(&amp;done);
}
void Tprint() {
for (int i = 0; i &lt; T; i++) {
P(&amp;done);
}
printf("sum = %ld\n", sum);
}
int main() {
SEM_INIT(&amp;done, 0);
for (int i = 0; i &lt; T; i++) {
create(Tsum);
}
create(Tprint);
}
</code></pre>

示例：fish-semfish-sem.c <p>代码示例：信号量实现同步习题</p> <p>任何并发计算任务都可以看作计算图上的一个拓扑排序 (调度)。因此，我们用信号量实现 happens-before 在原则上能够解决任何 “调度由完成任务的线程控制” 类型的并发同步问题。</p> <pre><code>#include "thread.h"
#include "thread-sync.h"
#define LENGTH(arr) (sizeof(arr) / sizeof(arr[0]))
enum { A = 1, B, C, D, E, F, };
struct rule {
int from, ch, to;
} rules[] = {
{ A, '&lt;', B },
{ B, '&gt;', C },
{ C, '&lt;', D },
{ A, '&gt;', E },
{ E, '&lt;', F },
{ F, '&gt;', D },
{ D, '_', A },
};
int current = A;
sem_t cont[128];
void fish_before(char ch) {
P(&amp;cont[(int)ch]);
// Update state transition
for (int i = 0; i &lt; LENGTH(rules); i++) {
struct rule *rule = &amp;rules[i];
if (rule-&gt;from == current &amp;&amp; rule-&gt;ch == ch) {
current = rule-&gt;to;
}
}
}
void fish_after(char ch) {
int choices[16], n = 0;
// Find enabled transitions
for (int i = 0; i &lt; LENGTH(rules); i++) {
struct rule *rule = &amp;rules[i];
if (rule-&gt;from == current) {
choices[n++] = rule-&gt;ch;
}
}
// Activate a random one
int c = rand() % n;
V(&amp;cont[choices[c]]);
}
const char roles[] = ".&lt;&lt;&lt;&lt;&lt;&gt;&gt;&gt;&gt;___";
void fish_thread(int id) {
char role = roles[id];
while (1) {
fish_before(role);
putchar(role);  // Not lock-protected
fish_after(role);
}
}
int main() {
setbuf(stdout, NULL);
SEM_INIT(&amp;cont['&lt;'], 1);
SEM_INIT(&amp;cont['&gt;'], 0);
SEM_INIT(&amp;cont['_'], 0);
for (int i = 0; i &lt; strlen(roles); i++)
create(fish_thread);
}
</code></pre> <p> </p>

示例：spinlock-xv6spinlock-xv6.cthread.hthread-sync.h <p>代码示例：xv6 自旋锁实现</p> <p>xv6 自旋锁是防御性编程的典范。他假设锁的使用者会犯各种类型的错误，包括 AA 型死锁、double release、释放非本处理器持有的锁等。</p> <pre><code>#include "thread.h"
#include "thread-sync.h"
struct cpu {
int ncli;
};
struct spinlock {
const char *name;
int locked;
struct cpu *cpu;
};
__thread struct cpu lcpu;
struct cpu *mycpu() {
return &amp;lcpu;
}
#define panic(...) \
  do { \
    fprintf(stderr, "Panic %s:%d ", __FILE__, __LINE__); \
    fprintf(stderr, __VA_ARGS__); \
    fprintf(stderr, "\n"); \
    abort(); \
  } while (0) \
void
initlock(struct spinlock *lk, char *name)
{
lk-&gt;name = name;
lk-&gt;locked = 0;
lk-&gt;cpu = 0;
}
// Pushcli/popcli are like cli/sti except that they are matched:
// it takes two popcli to undo two pushcli.  Also, if interrupts
// are off, then pushcli, popcli leaves them off.
void
pushcli(void)
{
// removes CPU-dependent code
// eflags = readeflags();
// cli();
// if(mycpu()-&gt;ncli == 0)
//   mycpu()-&gt;intena = eflags &amp; FL_IF;
mycpu()-&gt;ncli += 1;
}
void
popcli(void)
{
// removes CPU-dependent code
//if(readeflags()&amp;FL_IF)
//  panic("popcli - interruptible");
if(--mycpu()-&gt;ncli &lt; 0)
panic("popcli");
//if(mycpu()-&gt;ncli == 0 &amp;&amp; mycpu()-&gt;intena)
//  sti();
}
// Check whether this cpu is holding the lock.
int
holding(struct spinlock *lock)
{
int r;
pushcli();
r = lock-&gt;locked &amp;&amp; lock-&gt;cpu == mycpu();
popcli();
return r;
}
// Acquire the lock.
// Loops (spins) until the lock is acquired.
// Holding a lock for a long time may cause
// other CPUs to waste time spinning to acquire it.
void
acquire(struct spinlock *lk)
{
pushcli(); // disable interrupts to avoid deadlock.
if(holding(lk))
panic("acquire");
// The xchg is atomic.
while(atomic_xchg(&amp;lk-&gt;locked, 1) != 0)
;
// Tell the C compiler and the processor to not move loads or stores
// past this point, to ensure that the critical section's memory
// references happen after the lock is acquired.
__sync_synchronize();
// Record info about lock acquisition for debugging.
lk-&gt;cpu = mycpu();
}
// Release the lock.
void
release(struct spinlock *lk)
{
if(!holding(lk))
panic("release");
lk-&gt;cpu = 0;
// Tell the C compiler and the processor to not move loads or stores
// past this point, to ensure that all the stores in the critical
// section are visible to other cores before the lock is released.
// Both the C compiler and the hardware may re-order loads and
// stores; __sync_synchronize() tells them both not to.
__sync_synchronize();
// Release the lock, equivalent to lk-&gt;locked = 0.
// This code can't use a C assignment, since it might
// not be atomic. A real OS would use C atomics here.
asm volatile("movl $0, %0" : "+m" (lk-&gt;locked) : );
popcli();
}
struct spinlock lk;
#define N 10000000
long sum = 0;
void Tworker(int tid) {
lcpu = (struct cpu) { .ncli = 0 };
for (int i = 0; i &lt; N; i++) {
acquire(&amp;lk);
sum++;
release(&amp;lk);
}
}
int main() {
initlock(&amp;lk, "spinlock");
for (int i = 0; i &lt; 2; i++) {
create(Tworker);
}
join();
printf("sum = %ld\n", sum);
}
